namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly List<RecipeCategory> _categories;

    public RecipeService()
    {
        _categories = new List<RecipeCategory>
        {
            new() { Name = "Breakfast", Description = "Start your day right with these morning favorites", Icon = "🥞", RecipeCount = 2 },
            new() { Name = "Lunch", Description = "Quick and satisfying midday meals", Icon = "🥗", RecipeCount = 2 },
            new() { Name = "Dinner", Description = "Hearty evening meals for the whole family", Icon = "🍝", RecipeCount = 2 },
            new() { Name = "Desserts", Description = "Sweet treats to end any meal", Icon = "🍰", RecipeCount = 2 },
        };

        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Classic Pancakes", Category = "Breakfast", Ingredients = "2 cups flour\n2 eggs\n1.5 cups milk\n2 tbsp sugar\n1 tsp baking powder\nPinch of salt", Steps = "1. Mix dry ingredients in a bowl\n2. Whisk eggs and milk together\n3. Combine wet and dry ingredients\n4. Heat a griddle over medium heat\n5. Pour batter and cook until bubbles form\n6. Flip and cook until golden", AverageRating = 4.5, RatingCount = 12 },
            new() { Id = 2, Title = "Avocado Toast", Category = "Breakfast", Ingredients = "2 slices sourdough bread\n1 ripe avocado\nSalt and pepper\nRed pepper flakes\n1 tbsp lemon juice", Steps = "1. Toast bread until golden\n2. Mash avocado with lemon juice\n3. Spread on toast\n4. Season with salt, pepper, and red pepper flakes", AverageRating = 4.2, RatingCount = 8 },
            new() { Id = 3, Title = "Caesar Salad", Category = "Lunch", Ingredients = "1 head romaine lettuce\n1/2 cup croutons\n1/4 cup parmesan cheese\nCaesar dressing\nGrilled chicken (optional)", Steps = "1. Wash and chop romaine lettuce\n2. Toss with Caesar dressing\n3. Top with croutons and shaved parmesan\n4. Add grilled chicken if desired", AverageRating = 4.0, RatingCount = 6 },
            new() { Id = 4, Title = "Grilled Cheese Sandwich", Category = "Lunch", Ingredients = "2 slices white bread\n2 slices cheddar cheese\n1 tbsp butter", Steps = "1. Butter one side of each bread slice\n2. Place cheese between unbuttered sides\n3. Grill on medium heat until golden\n4. Flip and grill other side", AverageRating = 4.7, RatingCount = 15 },
            new() { Id = 5, Title = "Spaghetti Bolognese", Category = "Dinner", Ingredients = "400g spaghetti\n500g ground beef\n1 onion, diced\n2 cloves garlic\n400g canned tomatoes\n2 tbsp tomato paste\nFresh basil\nParmesan cheese", Steps = "1. Cook spaghetti according to package\n2. Brown ground beef in a pan\n3. Add onion and garlic, cook until soft\n4. Add tomatoes and paste, simmer 20 min\n5. Season with salt, pepper, and basil\n6. Serve sauce over pasta with parmesan", AverageRating = 4.8, RatingCount = 20 },
            new() { Id = 6, Title = "Chicken Stir Fry", Category = "Dinner", Ingredients = "2 chicken breasts, sliced\n2 cups mixed vegetables\n3 tbsp soy sauce\n1 tbsp sesame oil\n1 clove garlic\n1 tsp ginger\nRice for serving", Steps = "1. Cook rice according to package\n2. Heat sesame oil in a wok\n3. Stir fry chicken until cooked\n4. Add vegetables, garlic, and ginger\n5. Add soy sauce and toss\n6. Serve over rice", AverageRating = 4.3, RatingCount = 10 },
            new() { Id = 7, Title = "Chocolate Chip Cookies", Category = "Desserts", Ingredients = "2.25 cups flour\n1 cup butter, softened\n3/4 cup sugar\n3/4 cup brown sugar\n2 eggs\n1 tsp vanilla\n1 tsp baking soda\n2 cups chocolate chips", Steps = "1. Preheat oven to 375°F\n2. Cream butter and sugars\n3. Beat in eggs and vanilla\n4. Mix in flour and baking soda\n5. Fold in chocolate chips\n6. Drop spoonfuls onto baking sheet\n7. Bake 9-11 minutes until golden", AverageRating = 4.9, RatingCount = 25 },
            new() { Id = 8, Title = "Tiramisu", Category = "Desserts", Ingredients = "6 egg yolks\n3/4 cup sugar\n500g mascarpone\n2 cups heavy cream\n2 cups espresso, cooled\nLadyfinger biscuits\nCocoa powder", Steps = "1. Whisk egg yolks and sugar until thick\n2. Blend in mascarpone until smooth\n3. Whip cream and fold into mixture\n4. Dip ladyfingers in espresso\n5. Layer biscuits and cream in dish\n6. Refrigerate 4 hours\n7. Dust with cocoa powder before serving", AverageRating = 4.6, RatingCount = 18 },
        };
    }

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public List<Recipe> GetAllRecipes() => _recipes;

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);

        var category = _categories.FirstOrDefault(c => c.Name.Equals(recipe.Category, StringComparison.OrdinalIgnoreCase));
        if (category != null)
            category.RecipeCount++;
    }

    public void RateRecipe(int recipeId, int rating)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe != null)
        {
            var totalRating = recipe.AverageRating * recipe.RatingCount;
            recipe.RatingCount++;
            recipe.AverageRating = (totalRating + rating) / recipe.RatingCount;
        }
    }
}
"}

