@page "/recipes"
@page "/recipes/{CategoryName}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>Browse Recipes - RecipeShare</PageTitle>

<h1>📖 Browse Recipes</h1>

@if (string.IsNullOrEmpty(CategoryName))
{
    <p class="lead">Select a category to browse recipes</p>
    <div class="list-group">
        @foreach (var category in RecipeService.GetCategories())
        {
            <a href="recipes/@category.Name.ToLower()" class="list-group-item list-group-item-action d-flex justify-content-between align-items-center">
                <span>@category.Icon @category.Name</span>
                <span class="badge bg-primary rounded-pill">@category.RecipeCount</span>
            </a>
        }
    </div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="recipes">All Categories</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                                }
                            </span>
                            <small class="text-muted">(@recipe.AverageRating.ToString("F1")) - @recipe.RatingCount ratings</small>
                        </p>
                    </div>
                    <div class="card-footer">
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>

    @if (!recipes.Any())
    {
        <div class="alert alert-info">No recipes found in this category.</div>
    }
}

@code {
    [Parameter]
    public string? CategoryName { get; set; }

    private List<Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        if (!string.IsNullOrEmpty(CategoryName))
        {
            recipes = RecipeService.GetRecipesByCategory(CategoryName);
        }
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (recipe == null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="recipes">All Categories</a></li>
            <li class="breadcrumb-item"><a href="recipes/@recipe.Category.ToLower()">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <div class="card mb-4">
        <div class="card-body">
            <h4>Rate this Recipe</h4>
            <StarRating RecipeId="recipe.Id" CurrentRating="recipe.AverageRating" RatingCount="recipe.RatingCount" />
        </div>
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">🧾 Ingredients</h5></div>
                <div class="card-body">
                    <ul class="list-unstyled">
                        @foreach (var ingredient in recipe.Ingredients.Split('\n'))
                        {
                            <li class="mb-1">• @ingredient</li>
                        }
                    </ul>
                </div>
            </div>
        </div>
        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">👨‍🍳 Steps</h5></div>
                <div class="card-body">
                    @foreach (var step in recipe.Steps.Split('\n'))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="d-inline-block">
    <span class="fs-4">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span role="button" class="@(i <= displayRating ? "text-warning" : "text-muted")"
                  style="cursor: pointer;"
                  @onclick="() => Rate(star)"
                  @onmouseover="() => Hover(star)"
                  @onmouseout="ResetHover">★</span>
        }
    </span>
    <span class="ms-2 text-muted">
        @if (userRated)
        {
            <span class="text-success">✓ You rated @userRating star@(userRating != 1 ? "s" : "")</span>
        }
        else
        {
            <span>(@CurrentRating.ToString("F1") avg, @RatingCount ratings)</span>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int displayRating;
    private int userRating;
    private bool userRated;
    private bool hovering;

    protected override void OnParametersSet()
    {
        displayRating = (int)Math.Round(CurrentRating);
    }

    private void Hover(int star)
    {
        if (!userRated)
        {
            hovering = true;
            displayRating = star;
        }
    }

    private void ResetHover()
    {
        if (!userRated)
        {
            hovering = false;
            displayRating = (int)Math.Round(CurrentRating);
        }
    }

    private void Rate(int star)
    {
        if (!userRated)
        {
            userRating = star;
            userRated = true;
            displayRating = star;
            RecipeService.RateRecipe(RecipeId, star);
        }
    }
}

